const authHeader = $input.item.json.headers?.authorization || '';
const token = authHeader.replace('Bearer ', '');

if (token === 'mock-jwt-token-123') {
  return [{ json: { valid: true, user: { id: 1, role: 'Employee', email: 'employee@autohr.com' } } }];
